class Solution {
public:
    long long maxGCDScore(vector<int>& nums, int k) {
        int n = nums.size();
        long long res = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                vector<int> subarray(nums.begin() + i, nums.begin() + j + 1);
                long long score = getScore(subarray, k);
                res = max(res, score);
            }
        }
        return res;
    }

    long long getScore(vector<int>& subarray, int k) {
        int n = subarray.size();
        long long res = 0;
        for (int mask = 0; mask < (1 << n); mask++) {
            vector<int> temp = subarray;
            int cnt = 0;
            for (int i = 0; i < n; i++) {
                if ((mask >> i) & 1) {
                    temp[i] *= 2;
                    cnt++;
                }
            }
            if (cnt <= k) {
                long long gcd = temp[0];
                for (int i = 1; i < n; i++) {
                    gcd = __gcd(gcd, temp[i]);
                }
                res = max(res, (long long)n * gcd);
            }
        }
        return res;
    }
};

